import React, { useState, useEffect, useRef } from 'react';
import { useGamification } from '../context/GamificationContext';

import { Check, X, ArrowRight, RefreshCw, Trophy, Shuffle, Clock } from 'lucide-react';
import confetti from 'canvas-confetti';

const Quiz = ({ questions }) => {
    const [currentIndex, setCurrentIndex] = useState(0);
    const [selectedOption, setSelectedOption] = useState(null);
    const [isAnswered, setIsAnswered] = useState(false);
    const [score, setScore] = useState(0);
    const [showResults, setShowResults] = useState(false);
    const [shuffledQuestions, setShuffledQuestions] = useState(questions);
    const [isShuffled, setIsShuffled] = useState(false);
    const [elapsedSeconds, setElapsedSeconds] = useState(0);
    const startTimeRef = useRef(null);
    const [timeSpent, setTimeSpent] = useState(0);
    const [questionTimes, setQuestionTimes] = useState([]);

    const currentQuestion = shuffledQuestions[currentIndex];

    const { addXP, updateStreak } = useGamification();

    useEffect(() => {
        startTimeRef.current = Date.now();
        setElapsedSeconds(0);

        const timer = setInterval(() => {
            setElapsedSeconds(Math.floor((Date.now() - startTimeRef.current) / 1000));
        }, 1000);

        return () => clearInterval(timer);
    }, [currentIndex]);

    const shuffleQuestions = () => {
        const shuffled = [...questions].sort(() => Math.random() - 0.5);
        setShuffledQuestions(shuffled);
        setIsShuffled(true);
        restartQuiz();
    };

    const resetOrder = () => {
        setShuffledQuestions(questions);
        setIsShuffled(false);
        restartQuiz();
    };

    useEffect(() => {
        if (!isAnswered) return;

        const isCorrect = selectedOption === currentQuestion.correctIndex;
        const timeTaken = Math.floor((Date.now() - startTimeRef.current) / 1000);

        const stats = JSON.parse(localStorage.getItem('quiz_stats') || '{}');
        stats.totalQuestions = (stats.totalQuestions || 0) + 1;
        stats.correctAnswers = (stats.correctAnswers || 0) + (isCorrect ? 1 : 0);
        stats.totalTimeSpent = (stats.totalTimeSpent || 0) + timeTaken;
        localStorage.setItem('quiz_stats', JSON.stringify(stats));
    }, [isAnswered, selectedOption, currentQuestion.correctIndex]);

    const handleOptionClick = (index) => {
        if (isAnswered) return;

        const timeTaken = Math.floor((Date.now() - startTimeRef.current) / 1000);
        setQuestionTimes([...questionTimes, timeTaken]);

        setSelectedOption(index);
        setIsAnswered(true);

        const isCorrect = index === currentQuestion.correctIndex;
        if (isCorrect) {
            setScore(prev => prev + 1);
            addXP(10); // 10 XP per correct answer
        } else {
            addXP(2); // 2 XP for attempting but wrong
        }
    };

    const nextQuestion = () => {
        if (currentIndex < shuffledQuestions.length - 1) {
            setCurrentIndex(prev => prev + 1);
            setSelectedOption(null);
            setIsAnswered(false);
        } else {
            const totalTime = questionTimes.reduce((a, b) => a + b, 0);
            setTimeSpent(totalTime);
            setShowResults(true);

            // Completion Rewards
            updateStreak();
            addXP(50); // Bonus for finishing

            if (score / shuffledQuestions.length >= 0.7) {
                addXP(100); // Bonus for good score
                confetti({
                    particleCount: 150,
                    spread: 100,
                    origin: { y: 0.6 }
                });
            }
        }
    };

    const restartQuiz = () => {
        setCurrentIndex(0);
        setSelectedOption(null);
        setIsAnswered(false);
        setScore(0);
        setShowResults(false);
        setQuestionTimes([]);
        startTimeRef.current = Date.now();
        setElapsedSeconds(0);
    };

    if (showResults) {
        const percentage = Math.round((score / shuffledQuestions.length) * 100);
        const avgTime = Math.floor(timeSpent / shuffledQuestions.length);

        return (
            <motion.div
                initial={{ scale: 0.9, opacity: 0 }}
                animate={{ scale: 1, opacity: 1 }}
                className="max-w-md mx-auto bg-white rounded-3xl shadow-xl overflow-hidden text-center p-8 border border-indigo-50"
            >
                <div className="w-24 h-24 bg-yellow-100 rounded-full flex items-center justify-center mx-auto mb-6 text-yellow-600">
                    <Trophy size={48} />
                </div>
                <h2 className="text-3xl font-bold text-gray-900 mb-2">Quiz Completed!</h2>
                <div className="text-6xl font-black text-indigo-600 mb-4">{percentage}%</div>
                <p className="text-gray-600 mb-4">You answered {score} out of {shuffledQuestions.length} questions correctly.</p>

                <div className="bg-gray-50 rounded-xl p-4 mb-6 space-y-2">
                    <div className="flex justify-between text-sm">
                        <span className="text-gray-600">Total Time:</span>
                        <span className="font-bold text-gray-900">{Math.floor(timeSpent / 60)}m {timeSpent % 60}s</span>
                    </div>
                    <div className="flex justify-between text-sm">
                        <span className="text-gray-600">Avg per Question:</span>
                        <span className="font-bold text-gray-900">{avgTime}s</span>
                    </div>
                    <div className="flex justify-between text-sm">
                        <span className="text-gray-600">Accuracy:</span>
                        <span className={`font-bold ${percentage >= 70 ? 'text-green-600' : 'text-red-600'}`}>
                            {percentage}%
                        </span>
                    </div>
                </div>

                <button
                    onClick={restartQuiz}
                    className="w-full py-4 bg-indigo-600 text-white rounded-xl font-bold hover:bg-indigo-700 transition flex items-center justify-center gap-2"
                >
                    <RefreshCw size={20} /> Try Again
                </button>
            </motion.div>
        );
    }

    return (
        <div className="max-w-2xl mx-auto space-y-6">
            {/* Controls Bar */}
            <div className="flex justify-between items-center">
                <button
                    onClick={isShuffled ? resetOrder : shuffleQuestions}
                    className={`flex items-center gap-2 px-4 py-2 rounded-lg font-medium transition ${isShuffled
                        ? 'bg-indigo-100 text-indigo-700 hover:bg-indigo-200'
                        : 'bg-gray-100 text-gray-700 hover:bg-gray-200'
                        }`}
                >
                    <Shuffle size={18} />
                    {isShuffled ? 'Reset Order' : 'Shuffle'}
                </button>
                <div className="flex items-center gap-4">
                    <div className="text-sm font-medium text-gray-600">
                        Question {currentIndex + 1} / {shuffledQuestions.length}
                    </div>
                    <div className="flex items-center gap-1 text-sm text-gray-500">
                        <Clock size={16} />
                        <span>{elapsedSeconds}s</span>
                    </div>
                </div>
            </div>

            {/* Progress Bar */}
            <div className="w-full bg-gray-200 rounded-full h-2">
                <div
                    className="bg-indigo-600 h-2 rounded-full transition-all duration-300"
                    style={{ width: `${((currentIndex + 1) / shuffledQuestions.length) * 100}%` }}
                />
            </div>

            {/* Question Card */}
            <motion.div
                key={currentIndex}
                initial={{ opacity: 0, x: 20 }}
                animate={{ opacity: 1, x: 0 }}
                className="bg-white rounded-3xl shadow-lg border border-gray-200 p-8"
            >
                <h3 className="text-xl font-bold text-gray-900 mb-6 leading-relaxed">{currentQuestion.question}</h3>

                <div className="space-y-3">
                    {currentQuestion.options.map((option, index) => {
                        let stateStyles = "border-gray-200 text-gray-700 hover:border-indigo-300 hover:bg-indigo-50";

                        if (isAnswered) {
                            if (index === currentQuestion.correctIndex) {
                                stateStyles = "border-green-500 bg-green-50 text-green-800";
                            } else if (index === selectedOption) {
                                stateStyles = "border-red-500 bg-red-50 text-red-800";
                            } else {
                                stateStyles = "border-gray-100 opacity-50";
                            }
                        }

                        return (
                            <button
                                key={index}
                                onClick={() => handleOptionClick(index)}
                                disabled={isAnswered}
                                className={`w-full text-left p-4 rounded-xl border-2 transition-all font-medium ${stateStyles} ${!isAnswered ? 'cursor-pointer' : 'cursor-default'
                                    }`}
                            >
                                <div className="flex items-center justify-between">
                                    <span>{option}</span>
                                    {isAnswered && index === currentQuestion.correctIndex && (
                                        <Check className="text-green-600" size={20} />
                                    )}
                                    {isAnswered && index === selectedOption && index !== currentQuestion.correctIndex && (
                                        <X className="text-red-600" size={20} />
                                    )}
                                </div>
                            </button>
                        );
                    })}
                </div>

                {isAnswered && currentQuestion.explanation && (
                    <motion.div
                        initial={{ opacity: 0, y: -10 }}
                        animate={{ opacity: 1, y: 0 }}
                        className="mt-6 pt-6 border-t border-gray-200"
                    >
                        <p className="text-gray-700 text-sm">
                            <span className="font-bold text-gray-900">Explanation:</span> {currentQuestion.explanation}
                        </p>
                    </motion.div>
                )}
            </motion.div>

            {/* Next Button */}
            {isAnswered && (
                <motion.div
                    initial={{ opacity: 0, y: 10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="flex justify-end"
                >
                    <button
                        onClick={nextQuestion}
                        className="flex items-center gap-2 px-8 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition font-bold shadow-lg shadow-indigo-200"
                    >
                        {currentIndex < shuffledQuestions.length - 1 ? 'Next Question' : 'See Results'}
                        <ArrowRight size={20} />
                    </button>
                </motion.div>
            )}
        </div>
    );
};

export default Quiz;

import React, { useState, useEffect } from 'react';
import { useGamification } from '../context/GamificationContext';
import { supabase } from '../services/supabaseClient';
import { Target, Clock, Brain, Star, TrendingUp, Trophy, Flame } from 'lucide-react';

const StatsDashboard = () => {
    const { gameState } = useGamification();
    const [stats, setStats] = useState({
        totalQuestions: 0,
        correctAnswers: 0,
        totalTimeSpent: 0,
        cardsReviewed: 0,
        favorites: 0,
        difficulty: {
            easy: 0,
            medium: 0,
            hard: 0
        }
    });
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const fetchStats = async () => {
            try {
                const { data: { user } } = await supabase.auth.getUser();
                if (!user) {
                    setLoading(false);
                    return;
                }

                // 1. Fetch Flashcards (srs_repetitions > 0 means reviewed)
                const { data: cards, error: cardError } = await supabase
                    .from('flashcards')
                    .select('*');

                if (cardError) throw cardError;

                const reviewedCards = cards.filter(c => c.srs_repetitions > 0);
                const easy = cards.filter(c => c.srs_interval > 7).length; // Arbitrary "Easy" threshold
                const medium = cards.filter(c => c.srs_interval > 1 && c.srs_interval <= 7).length;
                const hard = cards.filter(c => c.srs_interval === 1 && c.srs_repetitions > 0).length;

                // 2. Fetch Quiz Stats (We need a table for this, or simulate from local for now if not migrated)
                // For now, we'll keep quiz stats local but plan to migrate later
                const quizStats = JSON.parse(localStorage.getItem('quiz_stats') || '{}');

                setStats({
                    totalQuestions: quizStats.totalQuestions || 0,
                    correctAnswers: quizStats.correctAnswers || 0,
                    totalTimeSpent: quizStats.totalTimeSpent || 0,
                    cardsReviewed: reviewedCards.length,
                    favorites: 0, // Need a favorites table or column
                    difficulty: { easy, medium, hard }
                });

            } catch (err) {
                console.error("Error fetching stats:", err);
            } finally {
                setLoading(false);
            }
        };

        fetchStats();
    }, []);

    const accuracy = stats.totalQuestions > 0
        ? Math.round((stats.correctAnswers / stats.totalQuestions) * 100)
        : 0;

    const formatTime = (seconds) => {
        const hours = Math.floor(seconds / 3600);
        const minutes = Math.floor((seconds % 3600) / 60);
        if (hours > 0) return `${hours}h ${minutes}m`;
        return `${minutes}m`;
    };

    if (loading) return <div className="p-8 text-center text-gray-500">Loading your progress...</div>;

    return (
        <div className="max-w-6xl mx-auto space-y-8 animate-fade-in">
            <div className="flex flex-col md:flex-row items-center justify-between gap-4">
                <div>
                    <h2 className="text-3xl font-bold text-gray-800 drop-shadow-sm">Study Statistics</h2>
                    <p className="text-gray-500 font-medium">Your journey to mastery</p>
                </div>

                {/* Gamification Badge */}
                <div className="flex gap-4">
                    <div className="bg-white border border-gray-100 shadow-sm px-6 py-3 rounded-2xl flex items-center gap-3 animate-float">
                        <div className="bg-yellow-500/10 p-2 rounded-full">
                            <Trophy className="w-6 h-6 text-yellow-500" />
                        </div>
                        <div>
                            <div className="text-sm text-gray-400 font-medium uppercase tracking-wider">Level {gameState.level}</div>
                            <div className="text-xl font-bold text-gray-800">{gameState.xp} XP</div>
                        </div>
                    </div>

                    <div className="bg-white border border-gray-100 shadow-sm px-6 py-3 rounded-2xl flex items-center gap-3 animate-float" style={{ animationDelay: '1s' }}>
                        <div className="bg-orange-500/10 p-2 rounded-full">
                            <Flame className="w-6 h-6 text-orange-500" />
                        </div>
                        <div>
                            <div className="text-sm text-gray-400 font-medium uppercase tracking-wider">Daily Streak</div>
                            <div className="text-xl font-bold text-gray-800">{gameState.streak} Days</div>
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Stats Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                <StatCard
                    icon={Target}
                    label="Quiz Accuracy"
                    value={`${accuracy}%`}
                    color="from-indigo-500 to-blue-500"
                    subtitle={`${stats.correctAnswers} / ${stats.totalQuestions} correct`}
                />
                <StatCard
                    icon={Clock}
                    label="Time Studied"
                    value={formatTime(stats.totalTimeSpent)}
                    color="from-purple-500 to-pink-500"
                    subtitle={`${stats.totalQuestions} questions answered`}
                />
                <StatCard
                    icon={Brain}
                    label="Cards Reviewed"
                    value={stats.cardsReviewed}
                    color="from-blue-500 to-cyan-500"
                    subtitle="Flashcards practiced"
                />
                <StatCard
                    icon={TrendingUp}
                    label="Mastery Level"
                    value={stats.difficulty.easy > 10 ? "Expert" : "Novice"}
                    color="from-green-500 to-emerald-500"
                    subtitle={`${stats.difficulty.easy} concepts mastered`}
                />
                <StatCard
                    icon={Trophy}
                    label="Focus Points"
                    value={(stats.cardsReviewed * 10) + (stats.correctAnswers * 50)}
                    color="from-red-500 to-rose-500"
                    subtitle="Based on activity"
                />
            </div>

            {/* Difficulty Breakdown */}
            {stats.cardsReviewed > 0 && (
                <div className="bg-white border border-gray-100 shadow-sm rounded-2xl p-8">
                    <h3 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
                        <Brain className="w-5 h-5 text-indigo-600" />
                        Knowledge Gap Analysis
                    </h3>
                    <div className="space-y-6">
                        <DifficultyBar label="Mastered (Easy)" value={stats.difficulty.easy} total={stats.cardsReviewed} color="bg-green-500" />
                        <DifficultyBar label="Learning (Medium)" value={stats.difficulty.medium} total={stats.cardsReviewed} color="bg-yellow-500" />
                        <DifficultyBar label="Struggling (Hard)" value={stats.difficulty.hard} total={stats.cardsReviewed} color="bg-red-500" />
                    </div>
                </div>
            )}
        </div>
    );
};

const StatCard = ({ icon: Icon, label, value, color, subtitle }) => (
    <div className="bg-white border border-gray-100 shadow-sm rounded-2xl p-6 relative overflow-hidden group hover:shadow-md transition-all">
        <div className={`absolute -right-6 -top-6 w-32 h-32 bg-gradient-to-br ${color} opacity-10 rounded-full blur-2xl group-hover:opacity-20 transition-opacity`} />

        <div className="flex items-start justify-between mb-4 relative z-10">
            <div className={`p-3 rounded-xl bg-gradient-to-br ${color} shadow-sm`}>
                <Icon size={24} className="text-white" />
            </div>
        </div>

        <div className="relative z-10">
            <div className="text-4xl font-bold text-gray-800 mb-1 tracking-tight">{value}</div>
            <div className="text-sm font-bold text-gray-400 uppercase tracking-wide">{label}</div>
            {subtitle && <div className="text-xs text-indigo-600 font-medium mt-2 bg-indigo-50 inline-block px-2 py-1 rounded-lg">{subtitle}</div>}
        </div>
    </div>
);

const DifficultyBar = ({ label, value, total, color }) => (
    <div>
        <div className="flex justify-between text-sm mb-2 font-medium">
            <span className="text-gray-700">{label}</span>
            <span className="text-gray-900">{Math.round((value / total) * 100)}% ({value})</span>
        </div>
        <div className="w-full bg-gray-100 rounded-full h-3 overflow-hidden">
            <div
                className={`${color} h-3 rounded-full transition-all duration-1000 ease-out shadow-sm`}
                style={{ width: `${(value / total) * 100}%` }}
            />
        </div>
    </div>
);

export default StatsDashboard;

import React, { createContext, useContext, useState, useEffect } from 'react';
import { supabase } from '../services/supabaseClient';
import { toast } from 'react-hot-toast';

const AuthContext = createContext();

export const useAuth = () => useContext(AuthContext);

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        // 1. Check active session on load
        const getSession = async () => {
            const { data: { session }, error } = await supabase.auth.getSession();
            if (session?.user) {
                setUser(session.user);
            }
            setLoading(false);
        };

        getSession();

        // 2. Listen for auth changes (Login, Logout, Auto-refresh)
        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
            setUser(session?.user ?? null);
            setLoading(false);
        });

        return () => subscription?.unsubscribe();
    }, []);

    const login = async (email, password) => {
        const { data, error } = await supabase.auth.signInWithPassword({
            email,
            password,
        });

        if (error) {
            toast.error(error.message);
            throw error;
        }

        toast.success("Welcome back!");
        return data.user;
    };

    const register = async (name, email, password) => {
        const { data, error } = await supabase.auth.signUp({
            email,
            password,
            options: {
                data: {
                    full_name: name, // This goes into user_metadata
                },
            },
        });

        if (error) {
            toast.error(error.message);
            throw error;
        }

        toast.success("Account created! Please check your email.");
        return data.user;
    };

    const logout = async () => {
        await supabase.auth.signOut();
        toast.success("Logged out successfully");
        setUser(null);
    };

    const loginWithGoogle = async () => {
        try {
            const { error } = await supabase.auth.signInWithOAuth({
                provider: 'google',
                options: {
                    redirectTo: `${window.location.origin}/dashboard`
                }
            });
            if (error) {
                toast.error(error.message);
                throw error;
            }
        } catch (error) {
            console.error(error);
            toast.error("Failed to login with Google");
        }
    };

    const value = {
        user,
        login,
        loginWithGoogle,
        register,
        logout,
        loading
    };

    return (
        <AuthContext.Provider value={value}>
            {!loading && children}
        </AuthContext.Provider>
    );
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import confetti from 'canvas-confetti';
import { toast } from 'react-hot-toast'; // We might need to add this package or use a simple alert/custom toast

const GamificationContext = createContext();

export const useGamification = () => useContext(GamificationContext);

export const GamificationProvider = ({ children }) => {
    const [gameState, setGameState] = useState(() => {
        const saved = localStorage.getItem('mindflow_gamification');
        return saved ? JSON.parse(saved) : {
            xp: 0,
            level: 1,
            streak: 0,
            lastStudyDate: null, // ISO string YYYY-MM-DD
            achievements: [] // Array of strings (achievement IDs)
        };
    });

    const [showLevelUp, setShowLevelUp] = useState(false);

    useEffect(() => {
        localStorage.setItem('mindflow_gamification', JSON.stringify(gameState));
    }, [gameState]);

    const getXpToNextLevel = (level) => {
        return level * 100 * 1.5; // Simple curve: 150, 300, 450...
    };

    const addXP = (amount) => {
        setGameState(prev => {
            let newXP = prev.xp + amount;
            let newLevel = prev.level;
            let leveledUp = false;

            const xpNeeded = getXpToNextLevel(newLevel);
            if (newXP >= xpNeeded) {
                newLevel++;
                newXP = newXP - xpNeeded;
                leveledUp = true;
            }

            if (leveledUp) {
                triggerLevelUpEffects();
            }

            return {
                ...prev,
                xp: newXP,
                level: newLevel
            };
        });
    };

    const triggerLevelUpEffects = () => {
        setShowLevelUp(true);
        confetti({
            particleCount: 200,
            spread: 160,
            origin: { y: 0.6 },
            colors: ['#FFD700', '#FFA500', '#FF4500']
        });

        // Auto hide modal after 3 seconds if we implement one
        setTimeout(() => setShowLevelUp(false), 3000);
    };

    const updateStreak = () => {
        const today = new Date().toISOString().split('T')[0];
        setGameState(prev => {
            if (prev.lastStudyDate === today) {
                return prev; // Already studied today
            }

            const yesterday = new Date();
            yesterday.setDate(yesterday.getDate() - 1);
            const yesterdayString = yesterday.toISOString().split('T')[0];

            let newStreak = prev.streak;

            if (prev.lastStudyDate === yesterdayString) {
                newStreak += 1; // Continued streak
            } else {
                newStreak = 1; // Broken streak or first day
            }

            return {
                ...prev,
                streak: newStreak,
                lastStudyDate: today
            };
        });
    };

    const unlockAchievement = (id) => {
        setGameState(prev => {
            if (prev.achievements.includes(id)) return prev;

            // New achievement unlocked!
            confetti({ particleCount: 50, spread: 50 });
            return {
                ...prev,
                achievements: [...prev.achievements, id]
            };
        });
    };

    return (
        <GamificationContext.Provider value={{
            gameState,
            addXP,
            updateStreak,
            unlockAchievement,
            getXpToNextLevel,
            showLevelUp,
            setShowLevelUp
        }}>
            {children}
        </GamificationContext.Provider>
    );
};

import React, { createContext, useContext, useState } from 'react';
import { extractTextFromPDF } from '../services/pdfProcessor';
import { generateContent, saveStudySet, loadDeck as fetchDeck } from '../services/api';
import { toast } from 'react-hot-toast';

const StudyContext = createContext();

export const useStudy = () => useContext(StudyContext);

export const StudyProvider = ({ children }) => {
    const [text, setText] = useState('');
    const [flashcards, setFlashcards] = useState([]);
    const [quiz, setQuiz] = useState([]);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState(null);
    const [refreshLibrary, setRefreshLibrary] = useState(0); // Trigger for library refresh
    const [stats, setStats] = useState({
        cardsReviewed: 0,
        correctAnswers: 0,
