        streak: 0
    });

    // --- FILE UPLOAD ---
    const handleFileUpload = async (file) => {
        setLoading(true);
        setError(null);
        try {
            let extractedText = '';
            if (file.type === 'application/pdf') {
                extractedText = await extractTextFromPDF(file);
            } else {
                extractedText = await file.text();
            }
            setText(extractedText);
            // Clear content
            setFlashcards([]);
            setQuiz([]);
        } catch (err) {
            setError("Failed to process file: " + err.message);
        } finally {
            setLoading(false);
        }
    };

    // --- GENERATE FLASHCARDS (AUTO-SAVE) ---
    const generateFlashcards = async () => {
        if (!text) return;
        setLoading(true);
        try {
            // Limit text context to ~5k-7k tokens to avoid rate limits
            const safeText = text.substring(0, 25000);
            const prompt = `Generate 15 flashcards based on the following text. 
      Return the result as a strictly formatted JSON array of objects. 
      Each object must have "question" and "answer" keys.
      Do not output any markdown formatting (like \`\`\`json), just the raw JSON.
      
      Text Content:
      ${safeText}`;

            const response = await generateContent(prompt, "You are a helpful study assistant that outputs strict JSON.");
            let content = response.content[0].text.replace(/```json/g, '').replace(/```/g, '').trim();
            const parsed = JSON.parse(content);

            setFlashcards(parsed);

            // AUTO-SAVE
            const saved = await saveSession('Auto-saved Flashcards ' + new Date().toLocaleTimeString(), parsed, []);
            if (saved) {
                toast.success("Flashcards generated & saved!");
                setRefreshLibrary(prev => prev + 1); // Trigger Refresh
            } else {
                toast.error("Generated, but auto-save failed.");
            }

        } catch (err) {
            console.error(err);
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    // --- GENERATE QUIZ (AUTO-SAVE) ---
    const generateQuiz = async () => {
        if (!text) return;
        setLoading(true);
        try {
            // Limit text context to ~5k-7k tokens to avoid rate limits
            const safeText = text.substring(0, 25000);
            const prompt = `Generate 15 multiple-choice questions based on the following text.
      Return the result as a strictly formatted JSON array of objects.
      Each object must have:
      - "question": string
      - "options": array of 4 strings
      - "correctIndex": number (0-3)
      - "explanation": string (brief explanation of why the answer is correct)
      
      Do not output any markdown formatting, just the raw JSON.
      
      Text Content:
      ${safeText}`;

            const response = await generateContent(prompt, "You are a helpful study assistant that outputs strict JSON.");
            let content = response.content[0].text.replace(/```json/g, '').replace(/```/g, '').trim();
            const parsed = JSON.parse(content);

            setQuiz(parsed);

            // AUTO-SAVE
            const saved = await saveSession('Auto-saved Quiz ' + new Date().toLocaleTimeString(), [], parsed);
            if (saved) {
                toast.success("Quiz generated & saved!");
                setRefreshLibrary(prev => prev + 1); // Trigger Refresh
            } else {
                toast.error("Generated, but auto-save failed.");
            }

        } catch (err) {
            console.error(err);
            setError(err.message);
        } finally {
            setLoading(false);
        }
    };

    const updateStats = (newStats) => {
        setStats(prev => ({ ...prev, ...newStats }));
    };

    // --- SAVE SESSION ---
    const saveSession = async (title, currentFlashcards = flashcards, currentQuiz = quiz) => {
        if (!currentFlashcards.length && !currentQuiz.length) {
            return false;
        }

        try {
            await saveStudySet({
                title,
                originalText: text,
                flashcards: currentFlashcards,
                quiz: currentQuiz
            });
            return true;
        } catch (err) {
            console.error("Save failed:", err);
            return false;
        }
    };

    // --- LOAD DECK (LIBRARY) ---
    const loadDeck = async (id) => {
        setLoading(true);
        try {
            const data = await fetchDeck(id);
            setText(data.description || ''); // Using description as context
            setFlashcards(data.flashcards || []);
            setQuiz(data.quiz || []);
            toast.success("Session loaded!");
        } catch (err) {
            setError("Failed to load deck: " + err.message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <StudyContext.Provider value={{
            text,
            flashcards,
            quiz,
            loading,
            error,
            stats,
            handleFileUpload,
            generateFlashcards,
            generateQuiz,
            saveSession,
            updateStats,
            loadDeck,
            refreshLibrary // Export trigger
        }}>
            {children}
        </StudyContext.Provider>
    );
};

import React, { useState } from 'react';
import { useStudy } from '../context/StudyContext';
import { useAuth } from '../context/AuthContext';
import { Layers, HelpCircle, AlertTriangle, CheckCircle, FileText, BarChart, BookOpen, Save, ArrowLeft } from 'lucide-react';
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import Flashcard from '../components/Flashcard';
import Quiz from '../components/Quiz';
import ReviewSheet from '../components/ReviewSheet';
import StatsDashboard from '../components/StatsDashboard';
import ChatInterface from '../components/ChatInterface';
import SRSDashboard from '../components/SRSDashboard';
import StudyLibrary from '../components/StudyLibrary';

const Study = () => {
    const { text, flashcards, quiz, generateFlashcards, generateQuiz, saveSession, loading, error } = useStudy();
    const { user } = useAuth();
    const [mode, setMode] = useState(() => text ? 'flashcards' : 'library');
    const navigate = useNavigate();
    const [saving, setSaving] = useState(false);
    const [saved, setSaved] = useState(false);

    const handleSave = async () => {
        if (!user) {
            alert("Please login to save your progress!");
            return;
        }
        setSaving(true);
        const success = await saveSession('Study Session ' + new Date().toLocaleDateString() + ' ' + new Date().toLocaleTimeString());
        if (success) {
            setSaved(true);
            setTimeout(() => setSaved(false), 3000);
        }
        setSaving(false);
    };

    if (!text && mode !== 'library') {
        return (
            <div className="flex flex-col items-center justify-center min-h-[60vh] text-center p-8">
                <motion.div
                    initial={{ scale: 0.8, opacity: 0 }}
                    animate={{ scale: 1, opacity: 1 }}
                    className="w-20 h-20 bg-yellow-50 text-yellow-500 rounded-full flex items-center justify-center mb-6"
                >
                    <BookOpen size={40} />
                </motion.div>
                <h2 className="text-3xl font-bold text-gray-900 mb-3">Time to Study!</h2>
                <p className="text-gray-500 mb-8 max-w-md">
                    Your workspace is empty. Upload a document to generate flashcards or open your library to review past sessions.
                </p>
                <div className="flex flex-col sm:flex-row gap-4 w-full justify-center">
                    <button
                        onClick={() => navigate('/')}
                        className="px-8 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 transition shadow-lg hover:shadow-indigo-200 font-semibold"
                    >
                        Upload Document
                    </button>
                    <button
                        onClick={() => setMode('library')}
                        className="px-8 py-3 bg-white text-gray-700 border border-gray-200 rounded-xl hover:bg-gray-50 transition font-semibold flex items-center justify-center gap-2"
                    >
                        <Layers size={20} />
                        Open Library
                    </button>
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
            {/* Header Section */}
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-10 gap-4">
                <div>
                    <h1 className="text-4xl font-extrabold text-gray-900 tracking-tight">
                        {mode === 'library' ? 'My Library' : 'Study Session'}
                    </h1>
                    <p className="text-gray-500 mt-1 text-lg">
                        {mode === 'library' ? 'Select a deck to review' : 'Master your material with AI-powered tools'}
                    </p>
                </div>

                <div className="flex gap-3 flex-wrap">
                    {mode !== 'library' && (flashcards.length > 0 || quiz.length > 0) && (
                        <button
                            onClick={handleSave}
                            disabled={saving}
                            className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-semibold transition-all duration-300 shadow-sm ${saved
                                ? 'bg-green-100 text-green-700 border border-green-200'
                                : 'bg-white text-indigo-600 border border-indigo-100 hover:border-indigo-300 hover:shadow-md'
                                }`}
                        >
                            {saved ? <CheckCircle size={18} /> : <Save size={18} />}
                            {saved ? 'Saved!' : 'Save Progress'}
                        </button>
                    )}

                    <button
                        onClick={() => setMode('library')}
                        className={`flex items-center gap-2 px-5 py-2.5 rounded-xl font-semibold transition-all duration-300 ${mode === 'library'
                            ? 'bg-indigo-600 text-white shadow-indigo-200 shadow-lg ring-2 ring-indigo-600 ring-offset-2'
                            : 'bg-white text-gray-600 border border-gray-200 hover:bg-gray-50 hover:text-gray-900'
                            }`}
                    >
                        {mode === 'library' ? <Layers size={20} /> : <ArrowLeft size={20} />}
                        {mode === 'library' ? 'Library' : 'Back to Library'}
                    </button>

                    {(flashcards.length > 0 || quiz.length > 0) && mode !== 'library' && (
                        <div className="hidden sm:flex items-center gap-2 px-4 py-2 bg-green-50 text-green-700 rounded-xl font-medium border border-green-100">
                            <CheckCircle size={16} />
                            <span className="text-sm">Auto-Saved</span>
                        </div>
                    )}
                </div>
            </div>

            {error && (
                <motion.div
                    initial={{ opacity: 0, y: -10 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="mb-8 bg-red-50 border border-red-100 text-red-700 px-6 py-4 rounded-xl flex items-center gap-3 shadow-sm"
                >
                    <AlertTriangle size={24} />
                    <p className="font-medium">{error}</p>
                </motion.div>
            )}

            <AnimatePresence mode="wait">
                {mode === 'library' ? (
                    <motion.div
                        key="library"
                        initial={{ opacity: 0, y: 20 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -20 }}
                        transition={{ duration: 0.3 }}
                    >
                        <StudyLibrary onSelect={setMode} />
                    </motion.div>
                ) : (
                    <motion.div
                        key="study-content"
                        initial={{ opacity: 0 }}
                        animate={{ opacity: 1 }}
                        exit={{ opacity: 0 }}
                    >
                        {/* Mode Navigation Tabs */}
                        <div className="flex justify-center gap-2 sm:gap-4 mb-10 overflow-x-auto pb-2 scrollbar-hide">
                            {[
                                { id: 'flashcards', icon: Layers, label: 'Flashcards' },
                                { id: 'quiz', icon: HelpCircle, label: 'Quiz Mode' },
                                { id: 'review', icon: FileText, label: 'Cheat Sheet' },
                                { id: 'stats', icon: BarChart, label: 'Statistics' }
                            ].map((tab) => (
                                <button
                                    key={tab.id}
                                    onClick={() => setMode(tab.id)}
                                    className={`flex items-center gap-2 px-6 py-3 rounded-xl transition-all font-semibold whitespace-nowrap ${mode === tab.id
                                        ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200 ring-2 ring-indigo-600 ring-offset-2'
                                        : 'bg-white text-gray-600 hover:bg-gray-50 border border-gray-200 hover:border-gray-300'
                                        }`}
                                >
                                    <tab.icon size={18} />
                                    {tab.label}
                                </button>
                            ))}
                        </div>

                        {/* SRS Upsell / Overview */}
                        <div className="mb-8">
                            <SRSDashboard />
                        </div>

                        <div className="min-h-[500px]">
                            <AnimatePresence mode="wait">
                                {mode === 'flashcards' && (
                                    <motion.div
                                        key="flashcards"
                                        initial={{ opacity: 0, x: 20 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        exit={{ opacity: 0, x: -20 }}
                                        transition={{ duration: 0.3 }}
                                    >
                                        {flashcards.length === 0 ? (
                                            <div className="text-center py-24 bg-white rounded-3xl border border-dashed border-gray-200">
                                                <h3 className="text-2xl font-bold text-gray-900 mb-4">Generate Flashcards?</h3>
                                                <p className="text-gray-500 mb-8">AI will create study cards from your notes.</p>
                                                <button
                                                    onClick={generateFlashcards}
                                                    disabled={loading}
                                                    className="px-8 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all hover:-translate-y-1 disabled:opacity-50 disabled:translate-y-0"
                                                >
                                                    {loading ? 'Generating Magic...' : 'Generate with AI'}
                                                </button>
                                            </div>
                                        ) : (
                                            <Flashcard cards={flashcards} />
                                        )}
                                    </motion.div>
                                )}

                                {mode === 'quiz' && (
                                    <motion.div
                                        key="quiz"
                                        initial={{ opacity: 0, x: 20 }}
                                        animate={{ opacity: 1, x: 0 }}
                                        exit={{ opacity: 0, x: -20 }}
                                        transition={{ duration: 0.3 }}
                                    >
                                        {quiz.length === 0 ? (
                                            <div className="text-center py-24 bg-white rounded-3xl border border-dashed border-gray-200">
                                                <h3 className="text-2xl font-bold text-gray-900 mb-4">Ready for a Challenge?</h3>
                                                <p className="text-gray-500 mb-8">Test your knowledge with an AI-generated quiz.</p>
                                                <button
                                                    onClick={generateQuiz}
                                                    disabled={loading}
                                                    className="px-8 py-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all hover:-translate-y-1 disabled:opacity-50 disabled:translate-y-0"
                                                >
                                                    {loading ? 'Generating Questions...' : 'Generate Quiz'}
                                                </button>
                                            </div>
                                        ) : (
                                            <Quiz questions={quiz} />
                                        )}
                                    </motion.div>
                                )}

                                {mode === 'review' && (
                                    <motion.div
                                        key="review"
                                        initial={{ opacity: 0, scale: 0.95 }}
                                        animate={{ opacity: 1, scale: 1 }}
                                        exit={{ opacity: 0, scale: 0.95 }}
                                        transition={{ duration: 0.3 }}
                                    >
                                        <ReviewSheet flashcards={flashcards} />
                                    </motion.div>
                                )}

                                {mode === 'stats' && (
                                    <motion.div
                                        key="stats"
                                        initial={{ opacity: 0, y: 20 }}
                                        animate={{ opacity: 1, y: 0 }}
                                        exit={{ opacity: 0, y: -20 }}
                                        transition={{ duration: 0.3 }}
                                    >
                                        <StatsDashboard />
                                    </motion.div>
                                )}
                            </AnimatePresence>
                        </div>

                        {/* --- AI TUTOR CHAT (Floating) --- */}
                        <ChatInterface />
                    </motion.div>
                )}
            </AnimatePresence>
        </div>
    );
};

export default Study;
